module top_module(a,b,saidaULA,obf_Tula);input wire [3:0] a;
    input wire [3:0] b;
    input wire [2:0] obf_Tula;

    output reg [3:0] saidaULA;

    parameter
    ADD = 3'd0;

    always @(obf_Tula or a or b)
    begin
        case(obf_Tula)
           ADD : saidaULA = a+b;
        endcase
    end
endmodule
